// ─── Hoja de estilos global "Azul & Gris" ─────────────────────────────
// El archivo usa cientos de clases de Tailwind con colores "a medida"
// escritos directamente (ej. text-[#1C3550], bg-[#EDF2F8]) en vez de
// nombres semánticos. En vez de reescribir cada una de esas clases una
// por una en todas las pantallas, esta hoja de estilos las traduce
// todas de golpe al nuevo azul/gris/blanco, de forma coherente y sin riesgo de dejar alguna pantalla a medias.
function EstiloGlobalAzulGris() {
  return (
    <style>{`
      body { background: #EFF4F9; }
      * { -webkit-font-smoothing: antialiased; }

      input, select, textarea {
        background-color: #FFFFFF;
        color: #1C3550;
      }
      input::placeholder, textarea::placeholder { color: #9AA9BC; }

      ::-webkit-scrollbar { width: 10px; height: 10px; }
      ::-webkit-scrollbar-thumb { background: rgba(62,124,184,0.28); border-radius: 999px; }
      ::-webkit-scrollbar-track { background: transparent; }
    `}</style>
  );
}

function fechaCorta(ts) {
  if (!ts) return "—";
  const d = ts?.toDate ? ts.toDate() : new Date(ts);
  return d.toLocaleDateString("es-ES", { day: "2-digit", month: "2-digit", year: "numeric" });
}
function horaCorta(ts) {
  if (!ts) return "—";
  const d = ts?.toDate ? ts.toDate() : new Date(ts);
  return d.toLocaleTimeString("es-ES", { hour: "2-digit", minute: "2-digit" });
}
function euros(n) {
  return (Number(n) || 0).toLocaleString("es-ES", { style: "currency", currency: "EUR" });
}

