function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [cargando, setCargando] = useState(false);
  const [mostrarReset, setMostrarReset] = useState(false);
  const [resetEnviado, setResetEnviado] = useState(false);

  async function entrar(e) {
    e.preventDefault();
    setError(""); setCargando(true);
    try { await signInWithEmailAndPassword(auth, email, password); }
    catch { setError("Email o contraseña incorrectos."); }
    setCargando(false);
  }
  async function recuperar(e) {
    e.preventDefault();
    setError(""); setCargando(true);
    try { await sendPasswordResetEmail(auth, email); setResetEnviado(true); }
    catch { setError("No se pudo enviar el email. Revisa la dirección."); }
    setCargando(false);
  }

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: SIDEBAR_DARK }}>
      <div className="w-full max-w-sm">
        <div className="text-center mb-7">
          <div className="flex items-center justify-center gap-3">
            <img src={LOGO_GOLFB_AZUL} alt="Golf B" style={{ height: 44, objectFit: "contain" }} />
            <div className="w-px h-8" style={{ background: "rgba(255,255,255,0.15)" }} />
            <img src={LOGO_GCR} alt="Golf Ciudad Real" style={{ height: 44, objectFit: "contain", borderRadius: 6 }} />
          </div>
          <p className="text-white/60 text-sm mt-3">Proshop · Golf Ciudad Real</p>
        </div>
        <div className="rounded-2xl p-7" style={{ background: "rgba(255,255,255,0.04)", border: "1px solid rgba(174,184,194,0.2)" }}>
          {!mostrarReset ? (
            <form onSubmit={entrar} className="space-y-4">
              <div>
                <label className="block text-white/70 text-xs font-medium mb-1.5">Email</label>
                <input type="email" required autoFocus value={email} onChange={(e) => setEmail(e.target.value)} className={inputLoginCls} placeholder="tu@email.com" />
              </div>
              <div>
                <label className="block text-white/70 text-xs font-medium mb-1.5">Contraseña</label>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className={inputLoginCls} placeholder="••••••••" />
              </div>
              {error && <p className="text-red-300 text-xs bg-red-900/25 rounded-lg px-3 py-2">{error}</p>}
              <button type="submit" disabled={cargando} className="w-full font-semibold py-2.5 rounded-xl text-sm transition disabled:opacity-50" style={{ background: GOLD, color: SIDEBAR_DARK }}>
                {cargando ? "Entrando…" : "Entrar"}
              </button>
              <button type="button" onClick={() => { setMostrarReset(true); setError(""); }} className="w-full text-white/50 text-xs hover:text-[#8FB3D9] transition">
                ¿Olvidaste tu contraseña?
              </button>
            </form>
          ) : (
            <div className="space-y-4">
              {resetEnviado ? (
                <p className="text-emerald-300 text-sm bg-emerald-900/20 rounded-lg px-3 py-3">Te hemos enviado un email con instrucciones para recuperar tu contraseña.</p>
              ) : (
                <form onSubmit={recuperar} className="space-y-4">
                  <p className="text-white/60 text-xs">Introduce tu email y te enviaremos un enlace para restablecer tu contraseña.</p>
                  <input type="email" required autoFocus value={email} onChange={(e) => setEmail(e.target.value)} className={inputLoginCls} placeholder="tu@email.com" />
                  {error && <p className="text-red-300 text-xs bg-red-900/25 rounded-lg px-3 py-2">{error}</p>}
                  <button type="submit" disabled={cargando} className="w-full font-semibold py-2.5 rounded-xl text-sm transition disabled:opacity-50" style={{ background: GOLD, color: SIDEBAR_DARK }}>
                    {cargando ? "Enviando…" : "Enviar enlace"}
                  </button>
                </form>
              )}
              <button type="button" onClick={() => { setMostrarReset(false); setResetEnviado(false); setError(""); }} className="w-full text-white/50 text-xs hover:text-[#8FB3D9] transition">
                ← Volver al login
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

