// Últimas ventas como clasificación de torneo: cada fila lleva su
// número de posición en una insignia, la primera en dorado.
function UltimasVentas({ ventas }) {
  const filas = ventas.datos.slice(0, 6);
  return (
    <div>
      <p className="text-[12px] font-semibold tracking-[0.04em] text-[#1C3550] mb-3">ÚLTIMAS VENTAS</p>
      <Tarjeta className="overflow-hidden">
        {filas.length === 0 && (
          <p className="text-sm text-[#5B6B7E] px-5 py-5 text-center">Todavía no hay ventas registradas.</p>
        )}
        {filas.map((v, i) => (
          <div key={v.id} className="flex items-center gap-3.5 px-5 py-3.5 border-b border-[#E1E8F0] last:border-0">
            <span
              className="w-6 h-6 rounded-full flex items-center justify-center text-[11px] font-semibold flex-shrink-0"
              style={i === 0 ? { background: GOLD, color: PRIMARY_DARK } : { background: "#2A4560", color: "#9AA7B5" }}
            >
              {String(i + 1).padStart(2, "0")}
            </span>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-[#1C3550] truncate">Ticket #{v.numeroTicket}</p>
              <p className="text-[11.5px] text-[#5B6B7E] truncate">{v.empleadoNombre} · {horaCorta(v.creadoEn)}</p>
            </div>
            <span className="text-sm font-semibold flex-shrink-0" style={{ color: FAIRWAY_DEEP }}>{euros(v.total)}</span>
          </div>
        ))}
      </Tarjeta>
    </div>
  );
}

function Panel({ ventas, productos, fichajes, categorias, onAbrirVentas, cajaHoy, onIrCaja }) {
  const hoy = new Date().toDateString();
  const ventasHoy = ventas.datos.filter((v) => v.creadoEn?.toDate?.().toDateString() === hoy);
  const totalHoy = ventasHoy.reduce((s, v) => s + (v.total || 0), 0);
  const ticketMedio = ventasHoy.length ? totalHoy / ventasHoy.length : 0;
  const bajoStock = productos.datos.filter((p) => (p.stockActual ?? 0) <= (p.stockMinimo ?? 0));
  const fichadosAhora = fichajes.datos.filter((f) => f.entrada && !f.salida);

  return (
    <div>
      <Cabecera titulo="Panel de Proshop" subtitulo="Vista general de ventas, stock y personal." />

      {!cajaHoy && (
        <button
          onClick={onIrCaja}
          className="w-full flex items-center justify-between gap-3 rounded-xl px-5 py-3.5 mb-5 text-left hover:-translate-y-0.5 transition-all duration-200"
          style={{ background: "#E0B36829", border: "1px solid #E0B36855" }}
        >
          <span className="flex items-center gap-2.5 text-sm font-medium" style={{ color: "#E0B368" }}>
            <Lock size={16} strokeWidth={2} />
            La caja de hoy todavía no está abierta
          </span>
          <span className="text-sm font-semibold whitespace-nowrap" style={{ color: "#E0B368" }}>Abrir caja →</span>
        </button>
      )}

      <HeroVentas
        totalHoy={totalHoy}
        ventasHoyCount={ventasHoy.length}
        ticketMedio={ticketMedio}
        fichadosCount={fichadosAhora.length}
        bajoStockCount={bajoStock.length}
      />

      {categorias?.datos?.length > 0 && (
        <VentaRapida categorias={categorias} onAbrir={onAbrirVentas} />
      )}

      {bajoStock.length > 0 && (
        <Tarjeta className="p-6 mb-8">
          <p className="font-medium text-[#1C3550] mb-3">Productos por reponer</p>
          <div className="space-y-2">
            {bajoStock.slice(0, 6).map((p) => (
              <div key={p.id} className="flex items-center justify-between text-sm py-1.5 border-b border-[#E1E8F0] last:border-0">
                <span className="text-[#1C3550]">{p.nombre}</span>
                <Badge tone="ambar">{p.stockActual ?? 0} / mín. {p.stockMinimo ?? 0}</Badge>
              </div>
            ))}
          </div>
        </Tarjeta>
      )}

      <UltimasVentas ventas={ventas} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
// FICHAJES
// ════════════════════════════════════════════════════════════════════
function ModalPin({ open, onClose, empleado, onConfirmar }) {
  const [pin, setPin] = useState("");
  const [error, setError] = useState("");
  useEffect(() => { setPin(""); setError(""); }, [open]);
  if (!open) return null;
  function confirmar() {
    if (pin.length !== 4) { setError("El PIN debe tener 4 dígitos."); return; }
    const ok = !empleado.pin || pin === empleado.pin;
    if (!ok) { setError("PIN incorrecto."); return; }
    onConfirmar();
  }
  return (
    <Modal open={open} onClose={onClose} title={`PIN de ${empleado?.nombre || ""}`}>
      <Field label="Introduce tu PIN de 4 dígitos">
        <input autoFocus type="password" inputMode="numeric" maxLength={4} value={pin}
          onChange={(e) => setPin(e.target.value.replace(/\D/g, ""))} className={cx(inputCls, "text-center text-lg tracking-widest")} />
      </Field>
      {error && <p className="text-sm text-red-600 mb-3">{error}</p>}
      <BotonPrimario icon={KeyRound} onClick={confirmar}>Confirmar</BotonPrimario>
    </Modal>
  );
}

function Fichajes({ empleados, fichajes }) {
  const [modalPin, setModalPin] = useState(null); // { empleado, accion: "entrada"|"salida" }

  // ── Fuente central de personal: Golf B Máster ─────────────────────
  // Si hay fichas en golfb.es → 👷 Personal, fichan los trabajadores
  // activos del departamento Recepción (más los de Dirección, que
  // también pasan por recepción). El PIN se mantiene: se busca por
  // nombre en los empleados locales de Proshop. Si aún no hay fichas
  // en Máster, todo sigue funcionando con los empleados locales.
  const personalMaster = useColeccion("personal_empleados", "nombre", "asc");
  const usaMaster = personalMaster.datos.length > 0;
  const listaFichar = usaMaster
    ? personalMaster.datos
        .filter((e) => (e.estado || "activo") === "activo" && (e.departamento === "Recepción" || e.departamento === "Dirección"))
        .map((e) => {
          const local = empleados.datos.find((l) => (l.nombre || "").trim().toLowerCase() === (e.nombre || "").trim().toLowerCase());
          return { id: e.id, nombre: e.nombre, rol: e.puesto || e.departamento, pin: local?.pin || "" };
        })
    : empleados.datos;

  // Emparejamos por NOMBRE (no por id) para que los fichajes abiertos
  // sigan siendo válidos aunque cambie la fuente de empleados.
  const abiertoPara = useCallback((nombre) => fichajes.datos.find((f) => f.empleadoNombre === nombre && f.entrada && !f.salida), [fichajes.datos]);

  async function registrar() {
    const { empleado, accion, abierto } = modalPin;
    if (accion === "entrada") {
      await crearDoc("proshop_fichajes", { empleadoId: empleado.id, empleadoNombre: empleado.nombre, entrada: serverTimestamp(), salida: null });
    } else {
      await actualizarDoc("proshop_fichajes", abierto.id, { salida: serverTimestamp() });
    }
    setModalPin(null);
  }

  return (
    <div>
      <Cabecera titulo="Fichajes" subtitulo="Control de jornada del equipo de Proshop y Recepción." />
      {usaMaster && (
        <p className="text-xs text-[#5B6B7E] mb-4">
          ✅ Plantilla gestionada desde <span className="text-[#1C3550] font-medium">Golf B Máster → 👷 Personal</span> (departamentos Recepción y Dirección).
        </p>
      )}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5 mb-8">
        {listaFichar.map((e) => {
          const abierto = abiertoPara(e.nombre);
          return (
            <Tarjeta key={e.id} className="p-6">
              <p className="font-medium text-[#1C3550]">{e.nombre}</p>
              <p className="text-xs text-[#5B6B7E] mb-3">{e.rol}</p>
              {abierto ? (
                <>
                  <Badge tone="verde">En jornada desde {horaCorta(abierto.entrada)}</Badge>
                  <div className="mt-3">
                    <BotonSecundario icon={LogOut} onClick={() => setModalPin({ empleado: e, accion: "salida", abierto })}>Registrar salida</BotonSecundario>
                  </div>
                </>
              ) : (
                <div className="mt-1">
                  <BotonPrimario icon={LogIn} onClick={() => setModalPin({ empleado: e, accion: "entrada" })}>Registrar entrada</BotonPrimario>
                </div>
              )}
            </Tarjeta>
          );
        })}
      </div>

      <Tarjeta className="p-6">
        <p className="font-medium text-[#1C3550] mb-3">Historial reciente</p>
        <div className="space-y-2">
          {fichajes.datos.slice(0, 15).map((f) => (
            <div key={f.id} className="flex items-center justify-between text-sm py-1.5 border-b border-[#E1E8F0] last:border-0">
              <span className="text-[#1C3550]">{f.empleadoNombre}</span>
              <span className="text-[#5B6B7E]">{fechaCorta(f.entrada)} · {horaCorta(f.entrada)} → {f.salida ? horaCorta(f.salida) : "—"}</span>
            </div>
          ))}
          {fichajes.datos.length === 0 && <p className="text-sm text-[#5B6B7E]">Sin fichajes todavía.</p>}
        </div>
      </Tarjeta>

      <ModalPin open={!!modalPin} onClose={() => setModalPin(null)} empleado={modalPin?.empleado} onConfirmar={registrar} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
// CAJA DIARIA (apertura / cierre)
// ════════════════════════════════════════════════════════════════════

// Modal compartido para abrir o cerrar caja, con PIN del empleado y los
// campos propios de cada acción (fondo inicial al abrir, efectivo
// contado + notas al cerrar).
function ModalCaja({ open, onClose, accion, empleados, efectivoEsperado, onConfirmar }) {
  const [empleadoId, setEmpleadoId] = useState("");
  const [pin, setPin] = useState("");
  const [importe, setImporte] = useState("");
  const [notas, setNotas] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    if (open) { setEmpleadoId(empleados.datos[0]?.id || ""); setPin(""); setImporte(""); setNotas(""); setError(""); }
  }, [open]);

  if (!open) return null;
  const empleado = empleados.datos.find((e) => e.id === empleadoId);
  const esApertura = accion === "apertura";

  function confirmar() {
    if (!empleado) { setError("Selecciona un empleado."); return; }
    if (pin.length !== 4) { setError("El PIN debe tener 4 dígitos."); return; }
    if (empleado.pin && pin !== empleado.pin) { setError("PIN incorrecto."); return; }
    if (importe === "" || Number.isNaN(Number(importe))) { setError(esApertura ? "Indica el fondo inicial." : "Indica el efectivo contado."); return; }
    onConfirmar({ empleado, importe: Number(importe), notas });
  }

  return (
    <Modal open={open} onClose={onClose} title={esApertura ? "Abrir caja" : "Cerrar caja"}>
      <Field label="Empleado">
        <select className={inputCls} value={empleadoId} onChange={(e) => setEmpleadoId(e.target.value)}>
          {empleados.datos.map((e) => <option key={e.id} value={e.id}>{e.nombre}</option>)}
        </select>
      </Field>
      <Field label="PIN de 4 dígitos">
        <input type="password" inputMode="numeric" maxLength={4} value={pin}
          onChange={(e) => setPin(e.target.value.replace(/\D/g, ""))} className={cx(inputCls, "text-center text-lg tracking-widest")} />
      </Field>
      <Field label={esApertura ? "Fondo inicial en caja" : "Efectivo contado ahora"}>
        <input type="number" step="0.01" min="0" value={importe} onChange={(e) => setImporte(e.target.value)} className={inputCls} placeholder="0,00" />
      </Field>
      {!esApertura && (
        <p className="text-xs text-[#5B6B7E] -mt-2.5 mb-3.5">Efectivo esperado según ventas del día: <strong>{euros(efectivoEsperado)}</strong></p>
      )}
      <Field label="Notas (opcional)">
        <textarea rows={2} value={notas} onChange={(e) => setNotas(e.target.value)} className={inputCls} placeholder="Cualquier incidencia a registrar…" />
      </Field>
      {error && <p className="text-sm text-red-600 mb-3">{error}</p>}
      <BotonPrimario icon={esApertura ? Unlock : Lock} onClick={confirmar}>{esApertura ? "Abrir caja" : "Cerrar caja"}</BotonPrimario>
    </Modal>
  );
}

function ResumenDiferencia({ diferencia }) {
  const abs = Math.abs(diferencia);
  if (abs < 0.01) return <Badge tone="verde">Cuadra exacta</Badge>;
  const tone = abs <= 2 ? "ambar" : "rojo";
  const signo = diferencia > 0 ? "+" : "";
  return <Badge tone={tone}>{signo}{euros(diferencia)} {diferencia > 0 ? "sobra" : "falta"}</Badge>;
}

function Caja({ caja, ventas, empleados }) {
  const [modal, setModal] = useState(null); // "apertura" | "cierre" | null

  const hoyId = fechaId();
  const cajaHoy = caja.datos.find((c) => c.fecha === hoyId);
  const ventasHoy = ventas.datos.filter((v) => esHoy(v.creadoEn));
  const porMetodo = (metodo) => ventasHoy.filter((v) => v.metodoPago === metodo).reduce((s, v) => s + (v.total || 0), 0);
  const ventasEfectivo = porMetodo("Efectivo");
  const ventasTarjeta = porMetodo("Tarjeta");
  const ventasBono = porMetodo("Bono/Socio");
  const totalVentas = ventasEfectivo + ventasTarjeta + ventasBono;
  const efectivoEsperado = (cajaHoy?.fondoInicial || 0) + ventasEfectivo;

  async function abrirCaja({ empleado, importe, notas }) {
    await guardarDocId("proshop_caja", hoyId, {
      fecha: hoyId, estado: "abierta",
      fondoInicial: importe, notasApertura: notas,
      empleadoAperturaId: empleado.id, empleadoAperturaNombre: empleado.nombre,
      horaApertura: serverTimestamp(),
    });
    setModal(null);
  }
  async function cerrarCaja({ empleado, importe, notas }) {
    const diferencia = importe - efectivoEsperado;
    await guardarDocId("proshop_caja", hoyId, {
      estado: "cerrada",
      empleadoCierreId: empleado.id, empleadoCierreNombre: empleado.nombre,
      horaCierre: serverTimestamp(), notasCierre: notas,
      efectivoContado: importe, efectivoEsperado, diferencia,
      ventasEfectivo, ventasTarjeta, ventasBono, totalVentas,
    });
    setModal(null);
  }
  async function reabrirCaja() {
    await guardarDocId("proshop_caja", hoyId, { estado: "abierta" });
  }

  const historial = caja.datos.filter((c) => c.fecha !== hoyId).slice(0, 10);

  return (
    <div>
      <Cabecera titulo="Caja diaria" subtitulo="Apertura y cierre de caja, con arqueo de efectivo." />

      {!cajaHoy && (
        <Tarjeta className="p-8 text-center mb-8">
          <Lock size={28} className="mx-auto mb-3" style={{ color: MUTED_TEXT }} />
          <p className="font-medium text-[#1C3550] mb-1">La caja de hoy todavía no está abierta</p>
          <p className="text-sm text-[#5B6B7E] mb-5">Indica el fondo inicial para empezar a vender con el arqueo controlado.</p>
          <div className="flex justify-center">
            <BotonPrimario icon={Unlock} onClick={() => setModal("apertura")}>Abrir caja</BotonPrimario>
          </div>
        </Tarjeta>
      )}

      {cajaHoy?.estado === "abierta" && (
        <Tarjeta className="p-6 mb-8">
          <div className="flex items-start justify-between flex-wrap gap-3 mb-5">
            <div>
              <Badge tone="verde">Caja abierta</Badge>
              <p className="text-sm text-[#5B6B7E] mt-2">
                Abierta por {cajaHoy.empleadoAperturaNombre} a las {horaCorta(cajaHoy.horaApertura)} · Fondo inicial {euros(cajaHoy.fondoInicial)}
              </p>
            </div>
            <BotonPrimario icon={Lock} onClick={() => setModal("cierre")}>Cerrar caja</BotonPrimario>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Efectivo</p>
              <p className="text-base font-semibold text-[#1C3550]">{euros(ventasEfectivo)}</p>
            </div>
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Tarjeta</p>
              <p className="text-base font-semibold text-[#1C3550]">{euros(ventasTarjeta)}</p>
            </div>
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Bono/Socio</p>
              <p className="text-base font-semibold text-[#1C3550]">{euros(ventasBono)}</p>
            </div>
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Efectivo esperado</p>
              <p className="text-base font-semibold" style={{ color: PRIMARY }}>{euros(efectivoEsperado)}</p>
            </div>
          </div>
        </Tarjeta>
      )}

      {cajaHoy?.estado === "cerrada" && (
        <Tarjeta className="p-6 mb-8">
          <div className="flex items-start justify-between flex-wrap gap-3 mb-5">
            <div>
              <Badge tone="neutral">Caja cerrada</Badge>
              <p className="text-sm text-[#5B6B7E] mt-2">
                Cerrada por {cajaHoy.empleadoCierreNombre} a las {horaCorta(cajaHoy.horaCierre)}
              </p>
            </div>
            <BotonSecundario icon={Unlock} onClick={reabrirCaja}>Reabrir caja</BotonSecundario>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-3 mb-4">
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Fondo inicial</p>
              <p className="text-base font-semibold text-[#1C3550]">{euros(cajaHoy.fondoInicial)}</p>
            </div>
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Efectivo esperado</p>
              <p className="text-base font-semibold text-[#1C3550]">{euros(cajaHoy.efectivoEsperado)}</p>
            </div>
            <div className="bg-[#EDF2F8] rounded-xl p-3.5">
              <p className="text-[11px] font-semibold text-[#5B6B7E] mb-1">Efectivo contado</p>
              <p className="text-base font-semibold text-[#1C3550]">{euros(cajaHoy.efectivoContado)}</p>
            </div>
          </div>
          <ResumenDiferencia diferencia={cajaHoy.diferencia || 0} />
          {cajaHoy.notasCierre && <p className="text-sm text-[#5B6B7E] mt-3">Notas: {cajaHoy.notasCierre}</p>}
        </Tarjeta>
      )}

      <Tarjeta className="p-6">
        <p className="font-medium text-[#1C3550] mb-3">Historial de cajas</p>
        <div className="space-y-2">
          {historial.map((c) => (
            <div key={c.id} className="flex items-center justify-between text-sm py-1.5 border-b border-[#E1E8F0] last:border-0">
              <span className="text-[#1C3550]">{fechaCorta(c.fecha)}</span>
              <span className="text-[#5B6B7E]">{c.estado === "cerrada" ? "Cerrada" : "Abierta"}</span>
              {c.estado === "cerrada" ? <ResumenDiferencia diferencia={c.diferencia || 0} /> : <Badge tone="ambar">Sin cerrar</Badge>}
            </div>
          ))}
          {historial.length === 0 && <p className="text-sm text-[#5B6B7E]">Todavía no hay días anteriores registrados.</p>}
        </div>
      </Tarjeta>

      <ModalCaja
        open={!!modal} onClose={() => setModal(null)} accion={modal}
        empleados={empleados} efectivoEsperado={efectivoEsperado}
        onConfirmar={modal === "apertura" ? abrirCaja : cerrarCaja}
      />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
// PRODUCTOS
// ════════════════════════════════════════════════════════════════════
function ModalProducto({ open, onClose, producto, categorias }) {
  const vacio = { nombre: "", categoria: categorias[0]?.nombre || "", precioVentaSinIVA: "", porcentajeIVA: IVA_DEFECTO, codigoBarras: "", stockActual: 0, stockMinimo: 3, unidad: "ud", proveedor: "", activo: true };
  const [form, setForm] = useState(vacio);
  useEffect(() => { setForm(producto ? { ...vacio, ...producto } : vacio); }, [producto, open]);

  async function guardar() {
    if (!form.nombre.trim()) return;
    const data = { ...form, precioVentaSinIVA: Number(form.precioVentaSinIVA) || 0, porcentajeIVA: Number(form.porcentajeIVA) || 0, stockActual: Number(form.stockActual) || 0, stockMinimo: Number(form.stockMinimo) || 0 };
    if (producto) await actualizarDoc("proshop_productos", producto.id, data);
    else await crearDoc("proshop_productos", data);
    onClose();
  }

  return (
    <Modal open={open} onClose={onClose} title={producto ? "Editar producto" : "Nuevo producto"} wide>
      <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-4">
        <Field label="Nombre del producto">
          <input className={inputCls} value={form.nombre} onChange={(e) => setForm({ ...form, nombre: e.target.value })} />
        </Field>
        <Field label="Categoría">
          <select className={inputCls} value={form.categoria} onChange={(e) => setForm({ ...form, categoria: e.target.value })}>
            {categorias.map((c) => <option key={c.id} value={c.nombre}>{c.nombre}</option>)}
          </select>
        </Field>
        <Field label="Precio de venta sin IVA (€)">
          <input type="number" step="0.01" className={inputCls} value={form.precioVentaSinIVA} onChange={(e) => setForm({ ...form, precioVentaSinIVA: e.target.value })} />
        </Field>
        <Field label="IVA (%)">
          <input type="number" className={inputCls} value={form.porcentajeIVA} onChange={(e) => setForm({ ...form, porcentajeIVA: e.target.value })} />
        </Field>
        <Field label="Código de barras / SKU (opcional)">
          <input className={inputCls} value={form.codigoBarras} onChange={(e) => setForm({ ...form, codigoBarras: e.target.value })} />
        </Field>
        <Field label="Proveedor (opcional)">
          <input className={inputCls} value={form.proveedor} onChange={(e) => setForm({ ...form, proveedor: e.target.value })} />
        </Field>
        <Field label="Stock actual">
          <input type="number" className={inputCls} value={form.stockActual} onChange={(e) => setForm({ ...form, stockActual: e.target.value })} />
        </Field>
        <Field label="Stock mínimo (aviso de reposición)">
          <input type="number" className={inputCls} value={form.stockMinimo} onChange={(e) => setForm({ ...form, stockMinimo: e.target.value })} />
        </Field>
      </div>
      <div className="pt-2"><BotonPrimario onClick={guardar}>Guardar producto</BotonPrimario></div>
    </Modal>
  );
}

function Productos({ productos, categorias }) {
  const [modal, setModal] = useState(null); // null | {} | producto
  const [filtro, setFiltro] = useState("Todas");
  const lista = filtro === "Todas" ? productos.datos : productos.datos.filter((p) => p.categoria === filtro);

  return (
    <div>
      <Cabecera titulo="Productos" subtitulo="Catálogo, precios e IVA del Proshop.">
        <BotonPrimario onClick={() => setModal({})}>Nuevo producto</BotonPrimario>
      </Cabecera>

      <div className="flex flex-wrap gap-2 mb-5">
        <PillFiltro activo={filtro === "Todas"} onClick={() => setFiltro("Todas")}>Todas</PillFiltro>
        {categorias.datos.map((c) => (
          <PillFiltro key={c.id} activo={filtro === c.nombre} onClick={() => setFiltro(c.nombre)}>{c.nombre}</PillFiltro>
        ))}
      </div>

      <Tarjeta className="overflow-hidden">
        <table className="w-full text-sm">
          <thead className="text-left">
            <tr className="border-b border-[#E1E8F0]">
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Producto</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Categoría</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Precio (IVA incl.)</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Stock</th>
              <th className="px-5 py-3.5"></th>
            </tr>
          </thead>
          <tbody>
            {lista.map((p) => {
              const conIVA = (p.precioVentaSinIVA || 0) * (1 + (p.porcentajeIVA || 0) / 100);
              const bajo = (p.stockActual ?? 0) <= (p.stockMinimo ?? 0);
              return (
                <tr key={p.id} className="border-b border-[#16324D] last:border-0 hover:bg-[#EDF2F8] transition-colors">
                  <td className="px-5 py-3">
                    <div className="flex items-center gap-3">
                      <Avatar nombre={p.nombre} />
                      <span className="text-[#1C3550] font-medium">{p.nombre}</span>
                    </div>
                  </td>
                  <td className="px-5 py-3 text-[#5B6B7E]">{p.categoria}</td>
                  <td className="px-5 py-3 text-[#1C3550] font-medium">{euros(conIVA)}</td>
                  <td className="px-5 py-3"><Badge tone={bajo ? "ambar" : "neutral"}>{p.stockActual ?? 0} {p.unidad}</Badge></td>
                  <td className="px-5 py-3 text-right">
                    <button onClick={() => setModal(p)} className="p-1.5 text-[#5B6B7E] hover:text-[#1C3550] rounded-lg hover:bg-[#EDF2F8] transition-colors"><Pencil size={15} /></button>
                    <button onClick={() => confirm(`¿Eliminar "${p.nombre}"?`) && borrarDoc("proshop_productos", p.id)} className="p-1.5 text-[#5B6B7E] hover:text-[#E2685C] rounded-lg hover:bg-[#E2685C29] transition-colors"><Trash2 size={15} /></button>
                  </td>
                </tr>
              );
            })}
            {lista.length === 0 && (
              <tr><td colSpan={5} className="px-5 py-8 text-center text-[#5B6B7E]">No hay productos en esta categoría todavía.</td></tr>
            )}
          </tbody>
        </table>
      </Tarjeta>

      <ModalProducto open={!!modal} onClose={() => setModal(null)} producto={modal?.id ? modal : null} categorias={categorias.datos} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
// VENTAS (TPV)
// ════════════════════════════════════════════════════════════════════
function TPV({ productos, empleados, siguienteTicket }) {
  const [carrito, setCarrito] = useState([]); // [{producto, cantidad}]
  const [empleadoId, setEmpleadoId] = useState(empleados.datos[0]?.id || "");
  const [metodoPago, setMetodoPago] = useState(METODOS_PAGO[0]);
  const [busqueda, setBusqueda] = useState("");
  const [guardando, setGuardando] = useState(false);

  const disponibles = productos.datos.filter((p) => p.activo !== false && p.nombre.toLowerCase().includes(busqueda.toLowerCase()));

  function añadir(p) {
    setCarrito((c) => {
      const existe = c.find((l) => l.producto.id === p.id);
      if (existe) return c.map((l) => l.producto.id === p.id ? { ...l, cantidad: l.cantidad + 1 } : l);
      return [...c, { producto: p, cantidad: 1 }];
    });
  }
  function cambiarCantidad(id, delta) {
    setCarrito((c) => c.map((l) => l.producto.id === id ? { ...l, cantidad: Math.max(1, l.cantidad + delta) } : l).filter((l) => l.cantidad > 0));
  }
  function quitar(id) { setCarrito((c) => c.filter((l) => l.producto.id !== id)); }

  const lineas = carrito.map((l) => {
    const { baseImponible, cuotaIVA, subtotal } = calcularLinea(l.producto.precioVentaSinIVA, l.producto.porcentajeIVA, l.cantidad);
    return { ...l, baseImponible, cuotaIVA, subtotal };
  });
  const baseImponibleTotal = lineas.reduce((s, l) => s + l.baseImponible, 0);
  const cuotaIVATotal = lineas.reduce((s, l) => s + l.cuotaIVA, 0);
  const total = baseImponibleTotal + cuotaIVATotal;

  async function cobrar() {
    if (lineas.length === 0 || guardando) return;
    setGuardando(true);
    const empleado = empleados.datos.find((e) => e.id === empleadoId);
    const numeroTicket = await siguienteTicket();
    await crearDoc("proshop_ventas", {
      numeroTicket,
      empleadoId, empleadoNombre: empleado?.nombre || "—",
      metodoPago,
      baseImponibleTotal, cuotaIVATotal, total,
      items: lineas.map((l) => ({
        productoId: l.producto.id, nombre: l.producto.nombre, cantidad: l.cantidad,
        precioUnitarioSinIVA: l.producto.precioVentaSinIVA, porcentajeIVA: l.producto.porcentajeIVA,
        baseImponible: l.baseImponible, cuotaIVA: l.cuotaIVA, subtotal: l.subtotal,
      })),
    });
    for (const l of lineas) {
      await actualizarDoc("proshop_productos", l.producto.id, { stockActual: Math.max(0, (l.producto.stockActual || 0) - l.cantidad) });
      await crearDoc("proshop_movimientosStock", { productoId: l.producto.id, tipo: "venta", cantidad: -l.cantidad, motivo: `Venta #${numeroTicket}`, empleadoId });
    }
    setCarrito([]);
    setGuardando(false);
  }

  return (
    <div>
      <Cabecera titulo="Ventas (TPV)" subtitulo="Registro rápido de ventas con IVA desglosado." />
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-5">
        <div className="lg:col-span-2">
          <input placeholder="Buscar producto…" value={busqueda} onChange={(e) => setBusqueda(e.target.value)} className={cx(inputCls, "mb-4")} />
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
            {disponibles.map((p) => (
              <Tarjeta key={p.id} className="p-4 cursor-pointer group" onClick={() => añadir(p)}>
                <div className="flex items-start justify-between mb-2">
                  <Avatar nombre={p.nombre} />
                  <div className="w-6 h-6 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity" style={{ background: PRIMARY }}>
                    <Plus size={13} color="white" strokeWidth={2.5} />
                  </div>
                </div>
                <p className="text-sm font-medium text-[#1C3550] line-clamp-2 leading-snug">{p.nombre}</p>
                <p className="text-xs text-[#5B6B7E] mb-1.5">{p.categoria}</p>
                <p className="text-base font-bold" style={{ color: PRIMARY }}>{euros((p.precioVentaSinIVA || 0) * (1 + (p.porcentajeIVA || 0) / 100))}</p>
              </Tarjeta>
            ))}
            {disponibles.length === 0 && <p className="text-sm text-[#5B6B7E] col-span-full py-6 text-center">Sin resultados.</p>}
          </div>
        </div>

        <Tarjeta className="p-5 self-start">
          <div className="flex items-center gap-2 mb-4">
            <div className="w-8 h-8 rounded-lg flex items-center justify-center" style={{ background: `${PRIMARY}15`, color: PRIMARY }}><Receipt size={15} /></div>
            <p className="font-semibold text-[#1C3550]">Ticket</p>
          </div>
          <div className="space-y-2.5 mb-4 max-h-64 overflow-y-auto">
            {lineas.map((l) => (
              <div key={l.producto.id} className="flex items-center justify-between text-sm gap-2 pb-2.5 border-b border-[#16324D] last:border-0 last:pb-0">
                <div className="flex-1 min-w-0">
                  <p className="truncate text-[#1C3550] font-medium">{l.producto.nombre}</p>
                  <p className="text-xs text-[#5B6B7E]">{euros(l.subtotal)}</p>
                </div>
                <div className="flex items-center gap-0.5 bg-[#EDF2F8] rounded-lg p-0.5">
                  <button onClick={() => cambiarCantidad(l.producto.id, -1)} className="p-1 rounded-md hover:bg-white transition-colors"><Minus size={13} /></button>
                  <span className="w-5 text-center text-[#1C3550] font-medium text-xs">{l.cantidad}</span>
                  <button onClick={() => cambiarCantidad(l.producto.id, 1)} className="p-1 rounded-md hover:bg-white transition-colors"><Plus size={13} /></button>
                </div>
                <button onClick={() => quitar(l.producto.id)} className="p-1 rounded-md hover:bg-[#E2685C29] text-[#5B6B7E] hover:text-[#E2685C] transition-colors"><Trash size={13} /></button>
              </div>
            ))}
            {lineas.length === 0 && <p className="text-sm text-[#5B6B7E]">Añade productos al ticket.</p>}
          </div>

          <Field label="Empleado">
            <select className={inputCls} value={empleadoId} onChange={(e) => setEmpleadoId(e.target.value)}>
              {empleados.datos.map((e) => <option key={e.id} value={e.id}>{e.nombre}</option>)}
            </select>
          </Field>
          <Field label="Método de pago">
            <select className={inputCls} value={metodoPago} onChange={(e) => setMetodoPago(e.target.value)}>
              {METODOS_PAGO.map((m) => <option key={m}>{m}</option>)}
            </select>
          </Field>

          <div className="rounded-xl p-3.5 mt-3 space-y-1" style={{ background: "#16324D" }}>
            <div className="flex justify-between text-xs text-[#5B6B7E]"><span>Base imponible</span><span>{euros(baseImponibleTotal)}</span></div>
            <div className="flex justify-between text-xs text-[#5B6B7E]"><span>IVA</span><span>{euros(cuotaIVATotal)}</span></div>
            <div className="flex justify-between text-xl font-bold pt-1.5 mt-1 border-t border-[#E1E8F0]" style={{ color: PRIMARY, fontFamily: "'Playfair Display', serif" }}><span>Total</span><span>{euros(total)}</span></div>
          </div>

          <div className="mt-4">
            <BotonPrimario icon={Receipt} onClick={cobrar} disabled={lineas.length === 0 || guardando}>{guardando ? "Guardando…" : "Cobrar y guardar ticket"}</BotonPrimario>
          </div>
        </Tarjeta>
      </div>
    </div>
  );
}

