// HISTORIAL DE VENTAS
// ════════════════════════════════════════════════════════════════════
function HistorialVentas({ ventas }) {
  const [abierta, setAbierta] = useState(null);
  return (
    <div>
      <Cabecera titulo="Historial de ventas" subtitulo="Todos los tickets emitidos, con IVA desglosado." />
      <Tarjeta className="overflow-hidden">
        <table className="w-full text-sm">
          <thead className="text-left">
            <tr className="border-b border-[#E1E8F0]">
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Ticket</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Fecha</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Empleado</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Pago</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Base</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">IVA</th>
              <th className="px-5 py-3.5 font-semibold text-[10.5px] uppercase tracking-wider text-[#5B6B7E]">Total</th>
            </tr>
          </thead>
          <tbody>
            {ventas.datos.map((v) => (
              <tr key={v.id} className="border-b border-[#16324D] last:border-0 hover:bg-[#EDF2F8] cursor-pointer transition-colors" onClick={() => setAbierta(v)}>
                <td className="px-5 py-3">
                  <div className="flex items-center gap-2.5">
                    <div className="w-8 h-8 rounded-lg flex items-center justify-center flex-shrink-0" style={{ background: `${GOLD}22`, color: "#8A6A2E" }}><Receipt size={14} /></div>
                    <span className="text-[#1C3550] font-medium">#{v.numeroTicket}</span>
                  </div>
                </td>
                <td className="px-5 py-3 text-[#5B6B7E]">{fechaCorta(v.creadoEn)} · {horaCorta(v.creadoEn)}</td>
                <td className="px-5 py-3 text-[#1C3550]">{v.empleadoNombre}</td>
                <td className="px-5 py-3"><Badge>{v.metodoPago}</Badge></td>
                <td className="px-5 py-3 text-[#5B6B7E]">{euros(v.baseImponibleTotal)}</td>
                <td className="px-5 py-3 text-[#5B6B7E]">{euros(v.cuotaIVATotal)}</td>
                <td className="px-5 py-3 font-semibold" style={{ color: PRIMARY }}>{euros(v.total)}</td>
              </tr>
            ))}
            {ventas.datos.length === 0 && <tr><td colSpan={7} className="px-5 py-8 text-center text-[#5B6B7E]">Sin ventas registradas todavía.</td></tr>}
          </tbody>
        </table>
      </Tarjeta>

      <Modal open={!!abierta} onClose={() => setAbierta(null)} title={abierta ? `Ticket #${abierta.numeroTicket}` : ""}>
        {abierta && (
          <div className="text-sm">
            <p className="text-[#5B6B7E] mb-3">{fechaCorta(abierta.creadoEn)} · {horaCorta(abierta.creadoEn)} · {abierta.empleadoNombre} · {abierta.metodoPago}</p>
            <div className="space-y-1.5 mb-3">
              {abierta.items?.map((it, i) => (
                <div key={i} className="flex justify-between">
                  <span className="text-[#1C3550]">{it.cantidad}× {it.nombre}</span>
                  <span className="text-[#5B6B7E]">{euros(it.subtotal)}</span>
                </div>
              ))}
            </div>
            <div className="border-t border-[#E1E8F0] pt-2 space-y-1">
              <div className="flex justify-between text-[#5B6B7E]"><span>Base imponible</span><span>{euros(abierta.baseImponibleTotal)}</span></div>
              <div className="flex justify-between text-[#5B6B7E]"><span>IVA</span><span>{euros(abierta.cuotaIVATotal)}</span></div>
              <div className="flex justify-between font-semibold" style={{ color: PRIMARY }}><span>Total</span><span>{euros(abierta.total)}</span></div>
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}

