// EQUIPO
// ════════════════════════════════════════════════════════════════════
function ModalEmpleado({ open, onClose, empleado }) {
  const vacio = { nombre: "", rol: "Recepción / Proshop", pin: "", activo: true };
  const [form, setForm] = useState(vacio);
  useEffect(() => { setForm(empleado ? { ...vacio, ...empleado } : vacio); }, [empleado, open]);
  async function guardar() {
    if (!form.nombre.trim()) return;
    if (empleado) await actualizarDoc("proshop_empleados", empleado.id, form);
    else await crearDoc("proshop_empleados", form);
    onClose();
  }
  return (
    <Modal open={open} onClose={onClose} title={empleado ? "Editar empleado" : "Nuevo empleado"}>
      <Field label="Nombre completo">
        <input className={inputCls} value={form.nombre} onChange={(e) => setForm({ ...form, nombre: e.target.value })} />
      </Field>
      <Field label="Rol">
        <input className={inputCls} value={form.rol} onChange={(e) => setForm({ ...form, rol: e.target.value })} />
      </Field>
      <Field label="PIN de fichaje (4 dígitos)">
        <input inputMode="numeric" maxLength={4} className={inputCls} value={form.pin} onChange={(e) => setForm({ ...form, pin: e.target.value.replace(/\D/g, "") })} />
      </Field>
      <div className="pt-2"><BotonPrimario onClick={guardar}>Guardar</BotonPrimario></div>
    </Modal>
  );
}

// Crea (o gestiona) el acceso de email/contraseña de un empleado:
// da de alta la cuenta en Firebase Auth, escribe su rol en la
// colección "Usuarios" y enlaza el email en el propio empleado.
function ModalAcceso({ open, onClose, empleado }) {
  const yaTieneAcceso = !!empleado?.email;
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [rolAcceso, setRolAcceso] = useState("proshop");
  const [error, setError] = useState("");
  const [cargando, setCargando] = useState(false);
  const [hecho, setHecho] = useState(false);

  useEffect(() => {
    if (open) {
      setEmail(empleado?.email || ""); setPassword(""); setRolAcceso(empleado?.rolAcceso || "proshop");
      setError(""); setHecho(false);
    }
  }, [open, empleado]);

  if (!open) return null;

  async function crear() {
    setError("");
    if (!/^\S+@\S+\.\S+$/.test(email)) { setError("Introduce un email válido."); return; }
    if (password.length < 6) { setError("La contraseña debe tener al menos 6 caracteres."); return; }
    setCargando(true);
    try {
      const uid = await crearCuentaSinDesconectar(email, password);
      await setDoc(docUsuario(uid), { email, role: rolAcceso, empleadoId: empleado.id, nombre: empleado.nombre, creadoEn: serverTimestamp() });
      await actualizarDoc("proshop_empleados", empleado.id, { email, authUid: uid, rolAcceso });
      setHecho(true);
    } catch (err) {
      if (err?.code === "auth/email-already-in-use") setError("Ya existe una cuenta con ese email.");
      else setError("No se pudo crear el acceso. Inténtalo de nuevo.");
    }
    setCargando(false);
  }

  async function enviarReset() {
    setCargando(true); setError("");
    try { await sendPasswordResetEmail(auth, empleado.email); setHecho(true); }
    catch { setError("No se pudo enviar el email de recuperación."); }
    setCargando(false);
  }

  return (
    <Modal open={open} onClose={onClose} title={yaTieneAcceso ? "Acceso de " + empleado.nombre : "Crear acceso para " + empleado?.nombre}>
      {yaTieneAcceso ? (
        <div>
          <p className="text-sm text-[#1C3550] mb-1">Este empleado ya puede entrar a Proshop con:</p>
          <p className="text-sm font-medium text-[#1C3550] mb-4 flex items-center gap-1.5"><Mail size={14} /> {empleado.email}</p>
          {hecho ? (
            <p className="text-sm text-[#2E6DA4] bg-[#EDF2F8] rounded-lg px-3 py-2.5 mb-2">Le hemos enviado un email para restablecer su contraseña.</p>
          ) : (
            <BotonSecundario icon={Mail} onClick={enviarReset}>{cargando ? "Enviando…" : "Enviarle enlace para restablecer contraseña"}</BotonSecundario>
          )}
          {error && <p className="text-sm text-red-600 mt-3">{error}</p>}
        </div>
      ) : (
        <div>
          <Field label="Email de acceso">
            <input type="email" className={inputCls} value={email} onChange={(e) => setEmail(e.target.value)} placeholder="empleado@golfciudadreal.es" />
          </Field>
          <Field label="Contraseña temporal (mín. 6 caracteres)">
            <input type="text" className={inputCls} value={password} onChange={(e) => setPassword(e.target.value)} placeholder="El empleado podrá cambiarla después" />
          </Field>
          <Field label="Rol de acceso">
            <select className={inputCls} value={rolAcceso} onChange={(e) => setRolAcceso(e.target.value)}>
              <option value="proshop">Proshop</option>
              <option value="recepcion">Recepción</option>
            </select>
          </Field>
          {error && <p className="text-sm text-red-600 mb-3">{error}</p>}
          <BotonPrimario icon={UserPlus} onClick={crear} disabled={cargando}>{cargando ? "Creando…" : "Crear acceso"}</BotonPrimario>
        </div>
      )}
    </Modal>
  );
}

function Equipo({ empleados }) {
  const [modal, setModal] = useState(null);
  const [modalAcceso, setModalAcceso] = useState(null);
  return (
    <div>
      <Cabecera titulo="Equipo" subtitulo="Personal de Proshop y Recepción.">
        <BotonPrimario onClick={() => setModal({})}>Nuevo empleado</BotonPrimario>
      </Cabecera>
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
        {empleados.datos.map((e) => (
          <Tarjeta key={e.id} className="p-6">
            <div className="flex items-center gap-3.5 mb-4">
              <Avatar nombre={e.nombre} />
              <div className="min-w-0">
                <p className="font-semibold text-[#1C3550] truncate">{e.nombre}</p>
                <p className="text-xs text-[#5B6B7E] truncate">{e.rol}</p>
              </div>
            </div>
            <div className="flex items-center gap-1.5 flex-wrap pt-3 border-t border-[#16324D]">
              <Badge tone={e.pin ? "verde" : "neutral"}>{e.pin ? "PIN configurado" : "Sin PIN"}</Badge>
              <Badge tone={e.email ? "verde" : "ambar"}>{e.email ? "Con acceso" : "Sin acceso"}</Badge>
              <button onClick={() => setModalAcceso(e)} title="Gestionar acceso" className="p-1.5 text-[#5B6B7E] hover:text-[#1C3550] rounded-lg hover:bg-[#EDF2F8] transition-colors ml-auto"><Mail size={15} /></button>
              <button onClick={() => setModal(e)} title="Editar" className="p-1.5 text-[#5B6B7E] hover:text-[#1C3550] rounded-lg hover:bg-[#EDF2F8] transition-colors"><Pencil size={15} /></button>
            </div>
          </Tarjeta>
        ))}
      </div>
      <ModalEmpleado open={!!modal} onClose={() => setModal(null)} empleado={modal?.id ? modal : null} />
      <ModalAcceso open={!!modalAcceso} onClose={() => setModalAcceso(null)} empleado={modalAcceso} />
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════
// APP PRINCIPAL
// ════════════════════════════════════════════════════════════════════
export default function App() {
  const { currentUser, userRole, cargandoAuth } = useAuthProshop();
  const [vista, setVista] = useState("panel");
  const [sidebarAbierto, setSidebarAbierto] = useState(false);

  const empleados = useColeccion("proshop_empleados", "nombre", "asc");
  const categorias = useColeccion("proshop_categorias", "orden", "asc");
  const productos = useColeccion("proshop_productos", "nombre", "asc");
  const ventas = useColeccion("proshop_ventas", "creadoEn", "desc");
  const fichajes = useColeccion("proshop_fichajes", "entrada", "desc");
  const ofertas = useColeccion("proshop_ofertas", "creadoEn", "desc");
  const caja = useColeccion("proshop_caja", "fecha", "desc");

  useSemillas(empleados, categorias);

  const siguienteTicket = useCallback(async () => {
    // Numeración secuencial simple basada en el nº de ventas existentes.
    return (ventas.datos.length || 0) + 1001;
  }, [ventas.datos.length]);

  const titulos = {
    panel: "Panel", ventas: "Ventas (TPV)", caja: "Caja diaria", historial: "Historial de ventas",
    fichajes: "Fichajes", productos: "Productos", ofertas: "Ofertas", equipo: "Equipo",
  };

  if (cargandoAuth) return <CargandoAuth />;
  if (!currentUser) return <Login />;
  if (!ROLES_PERMITIDOS_PROSHOP.includes(userRole)) return <AccesoPendiente email={currentUser.email} />;

  return (
    <div className="min-h-screen flex" style={{ background: BACKGROUND }}>
      <EstiloGlobalAzulGris />
      <Sidebar vista={vista} setVista={setVista} abierto={sidebarAbierto} setAbierto={setSidebarAbierto} currentUser={currentUser} userRole={userRole} />
      <div className="flex-1 min-w-0">
        <TopBar setAbierto={setSidebarAbierto} titulo={titulos[vista]} />
        <main className="p-4 md:p-10 max-w-6xl mx-auto">
          {vista === "panel" && (
            <Panel
              ventas={ventas}
              productos={productos}
              fichajes={fichajes}
              categorias={categorias}
              onAbrirVentas={() => setVista("ventas")}
              cajaHoy={caja.datos.find((c) => c.fecha === fechaId())}
              onIrCaja={() => setVista("caja")}
            />
          )}
          {vista === "ventas" && <TPV productos={productos} empleados={empleados} siguienteTicket={siguienteTicket} />}
          {vista === "caja" && <Caja caja={caja} ventas={ventas} empleados={empleados} />}
          {vista === "historial" && <HistorialVentas ventas={ventas} />}
          {vista === "fichajes" && <Fichajes empleados={empleados} fichajes={fichajes} />}
          {vista === "productos" && <Productos productos={productos} categorias={categorias} />}
          {vista === "ofertas" && <Ofertas ofertas={ofertas} productos={productos} />}
          {vista === "equipo" && <Equipo empleados={empleados} />}
        </main>
      </div>
    </div>
  );
}
